async (params, browser) => {
  // Search YouTube
  await browser.open(`https://www.youtube.com/results?search_query=${params.query}`)

  // Wait for search results
  await browser.waitForSelector('ytd-video-renderer', 15000)

  // Let results render
  await browser.wait(2000)

  // Scroll to load more results
  await browser.scroll({ direction: 'down', amount: 800 })

  await browser.wait(1500)

  // Extract search results
  const search_results = await browser.evaluate(`const results = []; const renderers = document.querySelectorAll('ytd-video-renderer'); for (let i = 0; i < Math.min(renderers.length, 10); i++) { const el = renderers[i]; const titleEl = el.querySelector('#video-title'); const channelEl = el.querySelector('ytd-channel-name #text a, ytd-channel-name #text'); const metaItems = el.querySelectorAll('#metadata-line span.inline-metadata-item, #metadata-line span'); const views = metaItems[0] ? metaItems[0].textContent.trim() : ''; const uploadedTime = metaItems[1] ? metaItems[1].textContent.trim() : ''; const durationEl = el.querySelector('badge-shape .badge-shape-wiz__text, ytd-thumbnail-overlay-time-status-renderer span, span.ytd-thumbnail-overlay-time-status-renderer'); const url = titleEl ? 'https://www.youtube.com' + titleEl.getAttribute('href') : ''; results.push({ title: titleEl ? titleEl.textContent.trim() : 'Unknown', channel: channelEl ? channelEl.textContent.trim() : '', views: views, uploaded: uploadedTime, duration: durationEl ? durationEl.textContent.trim() : '', url: url }); } return { result_count: results.length, results: results }`)

  return search_results
}
